module gray_code_counter_4(
   input                clk,
   input                rst_n,

   output reg [3:0]     Q
);
    reg [3:0] gray_code;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            gray_code <= 4'b0000;
            Q <= 4'b0000;
        end else begin
            gray_code <= gray_code + 1;
            Q <= gray_code ^ (gray_code >> 1);
        end
    end
endmodule
